#!/usr/bin/perl
use strict;
use warnings;
use Storable qw(nstore retrieve);
use CGI;
use Digest::MD5 qw(md5_hex);
use File::Path qw(make_path);
use File::Spec;

my $SESSION_DIR = '/tmp/perl_sessions';
my $SESSION_COOKIE_NAME = 'PERL_SESSION_ID';
my $SESSION_TIMEOUT = 3600;

make_path($SESSION_DIR) unless -d $SESSION_DIR;

sub generate_session_id {
    my $random = rand() . time() . $$ . rand();
    return md5_hex($random);
}

sub get_session_file {
    my ($session_id) = @_;
    return File::Spec->catfile($SESSION_DIR, "sess_$session_id");
}

sub create_session {
    my $session_id = generate_session_id();
    my $session_data = {
        session_id => $session_id,
        created_at => time(),
        last_access => time(),
        data => {}
    };
    
    my $session_file = get_session_file($session_id);
    nstore($session_data, $session_file);
    
    return ($session_id, $session_data);
}

sub load_session {
    my ($session_id) = @_;
    
    return undef unless $session_id;
    return undef unless $session_id =~ /^[a-f0-9]{32}$/;
    
    my $session_file = get_session_file($session_id);
    
    return undef unless -e $session_file;
    
    my $session_data = eval { retrieve($session_file) };
    return undef if $@;
    
    if (time() - $session_data->{last_access} > $SESSION_TIMEOUT) {
        destroy_session($session_id);
        return undef;
    }
    
    $session_data->{last_access} = time();
    save_session($session_id, $session_data);
    
    return $session_data;
}

sub save_session {
    my ($session_id, $session_data) = @_;
    
    my $session_file = get_session_file($session_id);
    nstore($session_data, $session_file);
}

sub destroy_session {
    my ($session_id) = @_;
    
    my $session_file = get_session_file($session_id);
    unlink $session_file if -e $session_file;
}

sub get_session_from_cookie {
    my ($cgi) = @_;
    
    my $session_id = $cgi->cookie($SESSION_COOKIE_NAME);
    
