}

sub delete_session_value {
    my ($session_id, $session_data, $key) = @_;
    
    delete $session_data->{data}{$key};
    save_session($session_id, $session_data);
}

sub cleanup_old_sessions {
    opendir(my $dh, $SESSION_DIR) or return;
    my @files = grep { /^sess_/ } readdir($dh);
    closedir($dh);
    
    foreach my $file (@files) {
        my $full_path = File::Spec->catfile($SESSION_DIR, $file);
        my $mtime = (stat($full_path))[9];
        
        if (time() - $mtime > $SESSION_TIMEOUT) {
            unlink $full_path;
        }
    }
}

